import React from "react";

const Skills = () => {
  const skills = [
    "Python", "C#", ".NET", "SQL", "PHP", "JavaScript", "HTML/CSS", "Bash",
    "Flask", "ASP.NET Core", "Git", "Azure DevOps", "Docker", "Kubernetes",
    "MySQL", "MS SQL Server", "Oracle", "REST APIs", "Postman", "Splunk"
  ];

  return (
    <section id="skills" className="py-20 px-6 bg-purple-50">
      <h2 className="text-3xl font-bold text-center mb-8">Skills</h2>
      <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-4 max-w-4xl mx-auto">
        {skills.map((skill) => (
          <div
            key={skill}
            className="p-3 bg-white shadow rounded text-center text-gray-800 hover:bg-purple-100 transition"
          >
            {skill}
          </div>
        ))}
      </div>
    </section>
  );
};

export default Skills;
